#include<bits/stdc++.h>
using namespace std;
int c[100010],u[100010];
vector<pair<int,int>> mp[100010];
int in[100010],out[100010];
int main()
{
    int n,p;
    scanf("%d%d",&n,&p);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&c[i],&u[i]);
    }
    for(int i=1;i<=p;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        in[v]++;
        out[u]++;
    }
    queue<int> q;
    for(int i=1;i<=n;i++)
    {
        if(in[i]==0)
        {
            // c[i]-=u[i];
            q.push(i);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(auto v:mp[t])
        {
            int i=v.first;
            in[i]--;
            if(c[t]>0)
            {
                c[i]+=c[t]*v.second;
            }
            if(in[i]==0)
            {
                c[i]-=u[i];
                q.push(i);
            }
        }
    }
    string s="NULL";
    for(int i=1;i<=n;i++)
    {
        if(out[i]==0&&c[i]>0)
        {
            s="";
            printf("%d %d\n",i,c[i]);
        }
    }
    cout<<s;
    return 0;
}
